# Define protobuf service definitions in user-auth and data retrieval services 
import grpc
from concurrent import futures
import time

class UserAuthServicer(grpc.Server): # Inherits from Server class of gRPC library to create a server instance for our microservices API  
    def authenticate_user(self, request, context): 
        print("Authenticating user...")        
        return grpc.helpers.unary_response('Success')     # Returning response back as 'success' in case of authentication success      
                                                         
class DataRetrievalServicer(grpc.Server):   # Inherits from Server class to create a server instance for data retrievals 
    def retrieve_data(self, request, context):    
        print("Data Retrieving...")        
        return grpc.helpers.unary_response('Success')      # Return response back as 'success' in case of successful retreival      
                                                         
# Create a server instance and bind it to port 50051  
server = UserAuthServicer(futures.ThreadPoolExecutor(max_workers=2))   
dataRetrievalServer = DataRetrievalServicer()     # Creating separate instances for data retrievals as well      
grpc.add_insecure_port(server, '[::]:50051')      # Binding server to port 50051 in secure mode (localhost)   
dataRetrievalServer.start()     # Starting the separate instance for data retrievals  
try:        
        while True :       # Main loop that will keep our gRPC servers running until we interrupt them with Ctrl+C     
            time.sleep(86400)  # Sleeping to maintain server's operation, in real world scenarios you should use a proper event-driven model  
except KeyboardInterrupt:     # When user presses CTRL + C it will stop the servers      
    print('Stopping gRPC Server...')     
finally :        
        dataRetrievalServer.stop(0)  # Stop server gracefully when we exit program or interruption occurs